import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import './App.css';

// API Configuration
const API_BASE = 'http://localhost:3001/api';

// Create API helper
const api = {
  get: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    const data = await res.json();
    return { data };
  },
  post: async (endpoint, body) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(body)
    });
    return { data: await res.json() };
  },
  put: async (endpoint, body) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(body)
    });
    return { data: await res.json() };
  },
  delete: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return { data: await res.json() };
  }
};

// Auth Context
const AuthContext = createContext(null);

const useAuth = () => useContext(AuthContext);

// Login Page
function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { username, password });
      if (res.data.token) {
        login(res.data.token, res.data.user);
      } else {
        setError(res.data.message || 'Login failed');
      }
    } catch (err) {
      setError('Connection error');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <div className="login-logo">
            <svg viewBox="0 0 100 100" className="logo-icon">
              <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
              <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
            </svg>
          </div>
          <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          <p>Member Management System</p>
        </div>
        <form onSubmit={handleSubmit}>
          {error && <div className="error-message">{error}</div>}
          <input type="text" placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} />
          <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
          <button type="submit">Login</button>
        </form>
        <div className="login-footer">
          <p>Default: admin/admin123</p>
        </div>
      </div>
    </div>
  );
}

// Dashboard
function Dashboard() {
  const [stats, setStats] = useState({ members: 0, loans: 0, shares: 0, savings: 0 });
  const { user } = useAuth();

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [membersRes, loansRes, sharesRes, savingsRes] = await Promise.all([
          api.get('/members'),
          api.get('/loans'),
          api.get('/shares'),
          api.get('/savings')
        ]);
        setStats({
          members: membersRes.data.data?.length || 0,
          loans: loansRes.data.data?.length || 0,
          shares: sharesRes.data.data?.length || 0,
          savings: savingsRes.data.data?.length || 0
        });
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };
    fetchStats();
  }, []);

  return (
    <div className="dashboard">
      <div className="welcome-section">
        <h1>Welcome, {user?.username || 'Admin'}</h1>
        <p>Sanaduk Saving and Credit Cooperative Ltd. - Member Management Dashboard</p>
      </div>
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Total Members</h3>
          <span className="stat-number">{stats.members}</span>
        </div>
        <div className="stat-card">
          <h3>Active Loans</h3>
          <span className="stat-number">{stats.loans}</span>
        </div>
        <div className="stat-card">
          <h3>Share Holders</h3>
          <span className="stat-number">{stats.shares}</span>
        </div>
        <div className="stat-card">
          <h3>Savings Accounts</h3>
          <span className="stat-number">{stats.savings}</span>
        </div>
      </div>
      <div className="dashboard-info">
        <div className="info-card">
          <h3>About Our Cooperative</h3>
          <p>Sanaduk Saving and Credit Cooperative Ltd. is dedicated to providing financial services to our members. We offer savings accounts, loans, and share investment opportunities to help our community grow together.</p>
        </div>
      </div>
    </div>
  );
}

// Members Page
function MembersPage() {
  const [members, setMembers] = useState([]);
  const [formData, setFormData] = useState({
    member_number: '', member_name: '', citizenship_number: '', 
    contact_number: '', address: '', email: '', join_date: '',
    membership_type: 'General', status: 'Active'
  });
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const res = await api.get('/members');
      setMembers(res.data.data || []);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/members/${editingId}`, formData);
      } else {
        await api.post('/members', formData);
      }
      setFormData({ member_number: '', member_name: '', citizenship_number: '', contact_number: '', address: '', email: '', join_date: '', membership_type: 'General', status: 'Active' });
      setEditingId(null);
      fetchMembers();
    } catch (error) {
      alert('Error saving member');
    }
  };

  const handleEdit = (member) => {
    setFormData(member);
    setEditingId(member.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this member?')) {
      try {
        await api.delete(`/members/${id}`);
        fetchMembers();
      } catch (error) {
        alert('Error deleting member');
      }
    }
  };

  const filteredMembers = members.filter(m =>
    m.member_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.member_number?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="members-page">
      <header className="page-header">
        <h1>Members Management</h1>
        <p>Manage cooperative members and their details</p>
      </header>
      <div className="form-section">
        <h2>{editingId ? 'Edit Member' : 'Add New Member'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <input type="text" placeholder="Member Number" value={formData.member_number} onChange={e => setFormData({...formData, member_number: e.target.value})} required />
            <input type="text" placeholder="Full Name" value={formData.member_name} onChange={e => setFormData({...formData, member_name: e.target.value})} required />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Citizenship Number" value={formData.citizenship_number} onChange={e => setFormData({...formData, citizenship_number: e.target.value})} />
            <input type="text" placeholder="Contact Number" value={formData.contact_number} onChange={e => setFormData({...formData, contact_number: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="email" placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="text" placeholder="Address" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="date" value={formData.join_date} onChange={e => setFormData({...formData, join_date: e.target.value})} />
            <select value={formData.membership_type} onChange={e => setFormData({...formData, membership_type: e.target.value})}>
              <option value="General">General</option>
              <option value="Founding">Founding</option>
              <option value="Life">Life</option>
            </select>
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
            </select>
          </div>
          <button type="submit">{editingId ? 'Update' : 'Add'} Member</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setFormData({ member_number: '', member_name: '', citizenship_number: '', contact_number: '', address: '', email: '', join_date: '', membership_type: 'General', status: 'Active' }) }}>Cancel</button>}
        </form>
      </div>
      <div className="filter-bar">
        <input type="text" placeholder="Search members..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr><th>Member No.</th><th>Name</th><th>Citizenship</th><th>Contact</th><th>Type</th><th>Status</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {filteredMembers.map(m => (
              <tr key={m.id}>
                <td>{m.member_number}</td>
                <td>{m.member_name}</td>
                <td>{m.citizenship_number}</td>
                <td>{m.contact_number}</td>
                <td>{m.membership_type}</td>
                <td><span className={`status-badge ${m.status?.toLowerCase()}`}>{m.status}</span></td>
                <td>
                  <button onClick={() => handleEdit(m)} className="btn-sm">Edit</button>
                  <button onClick={() => handleDelete(m.id)} className="btn-danger btn-sm">Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Loan Page
