// Savings Page
function SavingsPage() {
  const [savings, setSavings] = useState([]);
  const [members, setMembers] = useState([]);
  const [monthlyData, setMonthlyData] = useState({});
  const [selectedYear, setSelectedYear] = useState(2082);
  const [searchTerm, setSearchTerm] = useState('');

  const years = Array.from({ length: 16 }, (_, i) => 2075 + i);

  useEffect(() => {
    fetchData();
  }, [selectedYear]);

  const fetchData = async () => {
    try {
      const [savingsRes, membersRes, monthlyRes] = await Promise.all([
        api.get('/savings'),
        api.get('/members'),
        api.get('/monthly-savings/summary')
      ]);
      setSavings(savingsRes.data.data || []);
      setMembers(membersRes.data.data || []);
      
      const monthlyMap = {};
      const summaryData = monthlyRes.data.data;
      if (summaryData && summaryData.memberSummary) {
        summaryData.memberSummary.forEach(item => {
          monthlyMap[item.member_id] = {
            yearly_total: item.yearly_total,
            months_count: item.months_count
          };
        });
      }
      setMonthlyData(monthlyMap);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  const filteredSavings = savings.filter(s => {
    const matchesSearch = 
      s.account_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      getMemberName(s.member_id).toLowerCase().includes(searchTerm.toLowerCase());
    return matchesSearch;
  });

  return (
    <div className="savings-page">
      <header className="page-header">
        <h1>Savings Management</h1>
        <p>Member savings overview (Yearly totals from Monthly Savings)</p>
      </header>

      <div className="filter-bar">
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="filter-select"
        >
          {years.map(year => (
            <option key={year} value={year}>{year} B.S.</option>
          ))}
        </select>
        <input
          type="text"
          placeholder="Search by account number or member name..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
      </div>

      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Account No.</th>
              <th>Member</th>
              <th>Yearly Total (B.S.)</th>
              <th>Months Recorded</th>
            </tr>
          </thead>
          <tbody>
            {filteredSavings.map((saving) => (
              <tr key={saving.id}>
                <td>{saving.account_number}</td>
                <td>{getMemberName(saving.member_id)}</td>
                <td>Rs. {(monthlyData[saving.member_id]?.yearly_total || 0).toLocaleString()}</td>
                <td>{monthlyData[saving.member_id]?.months_count || 0}/12</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Monthly Savings Page
function MonthlySavingsPage() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [selectedYear, setSelectedYear] = useState(2082);
  const [monthlyData, setMonthlyData] = useState({});
  const [summary, setSummary] = useState(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const months = [
    { value: 1, name: 'Baisakh' },
    { value: 2, name: 'Jestha' },
    { value: 3, name: 'Ashadh' },
    { value: 4, name: 'Shrawan' },
    { value: 5, name: 'Bhadra' },
    { value: 6, name: 'Ashwin' },
    { value: 7, name: 'Kartik' },
    { value: 8, name: 'Mangsir' },
    { value: 9, name: 'Poush' },
    { value: 10, name: 'Magh' },
    { value: 11, name: 'Falgun' },
    { value: 12, name: 'Chaitra' }
  ];

  const nepaliMonths = [
    'Baisakh', 'Jestha', 'Ashadh', 'Shrawan', 'Bhadra', 'Ashwin',
    'Kartik', 'Mangsir', 'Poush', 'Magh', 'Falgun', 'Chaitra'
  ];

  const years = Array.from({ length: 16 }, (_, i) => 2075 + i);

  useEffect(() => {
    fetchMembers();
  }, []);

  useEffect(() => {
    if (selectedMember && selectedYear) {
      fetchMonthlyData();
      fetchSummary();
    }
  }, [selectedMember, selectedYear]);

  const fetchMembers = async () => {
    try {
      const { data } = await api.get('/members');
      setMembers(data.data || []);
    } catch (error) {
      console.error('Error fetching members:', error);
    }
  };

  const fetchMonthlyData = async () => {
    setLoading(true);
    try {
      const { data } = await api.get(`/monthly-savings?member_id=${selectedMember}&year=${selectedYear}`);
      const monthlyMap = {};
      (data.data || []).forEach(item => {
        monthlyMap[item.month] = item;
      });
      setMonthlyData(monthlyMap);
    } catch (error) {
      console.error('Error fetching monthly data:', error);
    }
    setLoading(false);
  };

  const fetchSummary = async () => {
    try {
      const url = selectedMember 
        ? `/monthly-savings/summary?year=${selectedYear}`
        : `/monthly-savings/summary?year=${selectedYear}`;
      const { data } = await api.get(url);
      setSummary(data.data);
    } catch (error) {
      console.error('Error fetching summary:', error);
    }
  };

  const handleSaveMonth = async (month) => {
    const amount = monthlyData[month]?.total_amount || 0;
    setSaving(true);
    try {
      await api.post('/monthly-savings', {
        member_id: selectedMember,
        year: selectedYear,
        month: month,
        month_name: nepaliMonths[month - 1],
        total_amount: amount
      });
      fetchMonthlyData();
      fetchSummary();
      alert('Monthly savings saved successfully!');
    } catch (error) {
      console.error('Error saving monthly savings:', error);
      alert('Error saving monthly savings');
    }
    setSaving(false);
  };

  const handleDeleteMonth = async (month) => {
    const entry = monthlyData[month];
    if (!entry?.id) return;
    
    if (!confirm('Are you sure you want to delete this entry?')) return;
    
    try {
      await api.delete(`/monthly-savings/${entry.id}`);
      fetchMonthlyData();
      fetchSummary();
    } catch (error) {
      console.error('Error deleting entry:', error);
      alert('Error deleting entry');
    }
  };

  const getYearlyTotal = () => {
    return Object.values(monthlyData).reduce((sum, item) => sum + (item.total_amount || 0), 0);
  };

  return (
    <div className="monthly-savings-page">
      <header className="page-header">
        <h1>Monthly Savings Management (B.S.)</h1>
        <p>Manage monthly savings for each member (Nepali Year)</p>
      </header>

      <div className="filter-bar">
        <select 
          value={selectedMember} 
          onChange={(e) => setSelectedMember(e.target.value)}
          className="filter-select"
        >
          <option value="">Select Member</option>
          {members.map(member => (
            <option key={member.id} value={member.id}>
              {member.member_number} - {member.member_name}
            </option>
          ))}
        </select>
        
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="filter-select"
        >
          {years.map(year => (
            <option key={year} value={year}>{year}</option>
          ))}
        </select>
      </div>

      {selectedMember && (
        <>
          {summary && (
            <div className="summary-cards">
              <div className="summary-card">
                <h3>Yearly Total Savings</h3>
                <span className="summary-value">Rs. {(summary.grandTotal || 0).toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Total This Year</h3>
                <span className="summary-value">Rs. {getYearlyTotal().toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Months Recorded</h3>
                <span className="summary-value">{Object.keys(monthlyData).length}/12</span>
              </div>
            </div>
          )}

          <div className="monthly-grid">
            <h3>Monthly Savings for {selectedYear}</h3>
            <div className="months-container">
              {months.map((month) => (
                <div key={month.value} className="month-card">
                  <div className="month-header">
                    <span className="month-name">{month.name}</span>
                    <span className="month-number">{month.value}</span>
                  </div>
                  <div className="month-input">
                    <label>Amount (Rs.)</label>
                    <input
                      type="number"
                      value={monthlyData[month.value]?.total_amount || ''}
                      onChange={(e) => setMonthlyData(prev => ({
                        ...prev,
                        [month.value]: {
                          ...prev[month.value],
                          total_amount: parseFloat(e.target.value) || 0
                        }
                      }))}
                      placeholder="0"
                    />
                  </div>
                  <div className="month-actions">
                    <button 
                      className="btn-primary btn-sm"
                      onClick={() => handleSaveMonth(month.value)}
                      disabled={saving}
                    >
                      Save
                    </button>
                    {monthlyData[month.value]?.id && (
                      <button 
                        className="btn-danger btn-sm"
                        onClick={() => handleDeleteMonth(month.value)}
                      >
                        Delete
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="yearly-overview">
            <h3>Yearly Overview</h3>
            <div className="yearly-chart">
              {months.map((month) => {
                const amount = monthlyData[month.value]?.total_amount || 0;
                const maxAmount = Math.max(...Object.values(monthlyData).map(m => m.total_amount || 0), 1);
                const height = maxAmount > 0 ? (amount / maxAmount) * 100 : 0;
                
                return (
                  <div key={month.value} className="chart-bar-container">
                    <div className="chart-bar" style={{ height: `${height}%` }}></div>
                    <span className="chart-label">{month.name.substring(0, 3)}</span>
                    <span className="chart-value">Rs. {amount.toLocaleString()}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function ProfilePage() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isEditingName, setIsEditingName] = useState(false);
  const [editName, setEditName] = useState('');
  const [profilePhoto, setProfilePhoto] = useState(null);

  useEffect(() => {
    fetchUser();
  }, []);

  const fetchUser = async () => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/me`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      setUser(data.data);
      setEditName(data.data?.username || '');
    } catch (error) {
      console.error('Error fetching user:', error);
    }
    setLoading(false);
  };

  const handleNameSave = async () => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/update-profile`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ username: editName })
      });
      const data = await res.json();
      if (data.success) {
        setUser({ ...user, username: editName });
        setIsEditingName(false);
        localStorage.setItem('user', JSON.stringify({ ...user, username: editName }));
      } else {
        alert(data.message || 'Error updating name');
      }
    } catch (error) {
      console.error('Error updating name:', error);
      alert('Error updating name');
    }
  };

  const handlePhotoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('photo', file);

    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/upload-photo`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });
      const data = await res.json();
      if (data.success) {
        setUser({ ...user, profile_photo: data.photoUrl });
        alert('Profile photo updated!');
      } else {
        alert(data.message || 'Error uploading photo');
      }
    } catch (error) {
      console.error('Error uploading photo:', error);
      alert('Error uploading photo');
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="profile-page">
      <header className="page-header">
        <h1>My Profile</h1>
        <p>View and manage your account</p>
      </header>
      <div className="profile-card">
        <div className="profile-header">
          <div className="profile-avatar-section">
            <div className="avatar">{
              user?.profile_photo 
                ? <img src={user.profile_photo} alt="Profile" style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover' }} />
                : user?.username?.charAt(0).toUpperCase() || 'A'
            }</div>
            <label className="avatar-upload">
              📷
              <input type="file" accept="image/*" onChange={handlePhotoUpload} />
            </label>
          </div>
          <div className="profile-info">
            {isEditingName ? (
              <>
                <div className="profile-name-input" style={{ display: 'block' }}>
                  <input 
                    type="text" 
                    value={editName} 
                    onChange={(e) => setEditName(e.target.value)}
                    placeholder="Enter your name"
                  />
                </div>
                <div style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
                  <button className="btn-primary btn-sm" onClick={handleNameSave}>Save</button>
                  <button className="name-edit-btn" onClick={() => setIsEditingName(false)}>Cancel</button>
                </div>
              </>
            ) : (
              <>
                <h2>{user?.username || 'Admin'}</h2>
                <button className="name-edit-btn" onClick={() => setIsEditingName(true)}>Edit Name</button>
              </>
            )}
            <p>{user?.role || 'Administrator'}</p>
          </div>
        </div>
        <div className="profile-details">
          <div className="detail-row">
            <span className="label">Username:</span>
            <span className="value">{user?.username}</span>
          </div>
          <div className="detail-row">
            <span className="label">Role:</span>
            <span className="value">{user?.role}</span>
          </div>
          {user?.email && (
            <div className="detail-row">
              <span className="label">Email:</span>
              <span className="value">{user.email}</span>
            </div>
          )}
          <div className="detail-row">
            <span className="label">Member Since:</span>
            <span className="value">{user?.created_at ? new Date(user.created_at).toLocaleDateString() : 'N/A'}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// Citizenship Page
function CitizenshipPage() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [citizenshipData, setCitizenshipData] = useState(null);
  const [formData, setFormData] = useState({
    citizenship_number: '', full_name: '', gender: '', birth_date: '', birth_date_bs: '',
    birth_place: '', nationality: 'Nepalese', religion: '', marital_status: '',
    issued_district: '', issued_date: '', province: '', district: '', municipality: '',
    ward_number: '', tole: '', phone: '', email: ''
  });
  const [photos, setPhotos] = useState({ photo: null, citizenship_front: null, citizenship_back: null });
  const [existingPhotos, setExistingPhotos] = useState({ photo: '', citizenship_front: '', citizenship_back: '' });
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    fetchMembers();
  }, []);

  useEffect(() => {
    if (selectedMember) {
      fetchCitizenship(selectedMember);
    } else {
      setCitizenshipData(null);
      setEditingId(null);
      resetForm();
    }
  }, [selectedMember]);

  const fetchMembers = async () => {
    try {
      const res = await api.get('/members');
      setMembers(res.data.data || []);
    } catch (error) {
      console.error('Error fetching members:', error);
    }
  };

  const fetchCitizenship = async (memberId) => {
    try {
      const res = await api.get(`/citizenship/${memberId}`);
      if (res.data.success) {
        setCitizenshipData(res.data.data);
        setFormData(res.data.data);
        setEditingId(res.data.data.id);
        setExistingPhotos({
          photo: res.data.data.photo || '',
          citizenship_front: res.data.data.citizenship_front || '',
          citizenship_back: res.data.data.citizenship_back || ''
        });
      } else {
        setCitizenshipData(null);
        setEditingId(null);
        resetForm();
      }
    } catch (error) {
      console.error('Error fetching citizenship:', error);
    }
  };

  const resetForm = () => {
    setFormData({
      citizenship_number: '', full_name: '', gender: '', birth_date: '', birth_date_bs: '',
      birth_place: '', nationality: 'Nepalese', religion: '', marital_status: '',
      issued_district: '', issued_date: '', province: '', district: '', municipality: '',
      ward_number: '', tole: '', phone: '', email: ''
    });
    setPhotos({ photo: null, citizenship_front: null, citizenship_back: null });
    setEditingId(null);
  };

  const handleFileChange = (e, field) => {
    const file = e.target.files[0];
    if (file) {
      setPhotos(prev => ({ ...prev, [field]: file }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedMember) {
      alert('Please select a member first');
      return;
    }

    setLoading(true);
    const formDataToSend = new FormData();
    formDataToSend.append('member_id', selectedMember);
    
    Object.keys(formData).forEach(key => {
      formDataToSend.append(key, formData[key]);
    });
    
    if (photos.photo) formDataToSend.append('photo', photos.photo);
    if (photos.citizenship_front) formDataToSend.append('citizenship_front', photos.citizenship_front);
    if (photos.citizenship_back) formDataToSend.append('citizenship_back', photos.citizenship_back);
    
    if (existingPhotos.photo) formDataToSend.append('existing_photo', existingPhotos.photo);
    if (existingPhotos.citizenship_front) formDataToSend.append('existing_citizenship_front', existingPhotos.citizenship_front);
    if (existingPhotos.citizenship_back) formDataToSend.append('existing_citizenship_back', existingPhotos.citizenship_back);

    try {
      const token = localStorage.getItem('token');
      const url = editingId 
        ? `${API_BASE}/citizenship/${editingId}`
        : `${API_BASE}/citizenship`;
      const method = editingId ? 'PUT' : 'POST';
      
      const res = await fetch(url, {
        method,
        headers: { 'Authorization': `Bearer ${token}` },
        body: formDataToSend
      });
      
      const data = await res.json();
      if (data.success) {
        alert(editingId ? 'Citizenship details updated!' : 'Citizenship details saved!');
        fetchCitizenship(selectedMember);
      } else {
        alert(data.message || 'Error saving citizenship');
      }
    } catch (error) {
      console.error('Error saving citizenship:', error);
      alert('Error saving citizenship');
    }
    setLoading(false);
  };

  const handleDelete = async () => {
    if (!editingId) return;
    if (!window.confirm('Are you sure you want to delete this citizenship details?')) return;

    try {
      await api.delete(`/citizenship/${editingId}`);
      alert('Citizenship details deleted!');
      setCitizenshipData(null);
      setEditingId(null);
      resetForm();
    } catch (error) {
      console.error('Error deleting citizenship:', error);
      alert('Error deleting citizenship');
    }
  };

  const viewPhoto = (photoUrl, title) => {
    if (photoUrl) {
      setShowModal(true);
    }
  };

  const getMemberName = (id) => {
    const member = members.find(m => m.id == id);
    return member ? member.member_name || member.member_number : 'Unknown';
  };

  return (
    <div className="citizenship-page">
      <header className="page-header">
        <h1>Citizenship Management</h1>
        <p>Manage member citizenship documents and details</p>
      </header>

      <div className="form-section">
        <h2>Select Member</h2>
        <div className="form-row">
          <select value={selectedMember} onChange={(e) => setSelectedMember(e.target.value)}>
            <option value="">Select a member</option>
            {members.map(m => (
              <option key={m.id} value={m.id}>
                {m.member_number} - {m.member_name}
              </option>
            ))}
          </select>
        </div>
      </div>

      {selectedMember && (
        <>
          <div className="form-section">
            <h2>{editingId ? 'Edit Citizenship Details' : 'Add Citizenship Details'}</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-row">
                <input type="text" placeholder="Citizenship Number" value={formData.citizenship_number} onChange={(e) => setFormData({...formData, citizenship_number: e.target.value})} required />
                <input type="text" placeholder="Full Name (as per citizenship)" value={formData.full_name} onChange={(e) => setFormData({...formData, full_name: e.target.value})} required />
              </div>
              <div className="form-row">
                <select value={formData.gender} onChange={(e) => setFormData({...formData, gender: e.target.value})}>
                  <option value="">Select Gender</option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                </select>
                <input type="date" placeholder="Birth Date (AD)" value={formData.birth_date} onChange={(e) => setFormData({...formData, birth_date: e.target.value})} />
                <input type="text" placeholder="Birth Date (BS)" value={formData.birth_date_bs} onChange={(e) => setFormData({...formData, birth_date_bs: e.target.value})} />
              </div>
              <div className="form-row">
                <input type="text" placeholder="Birth Place" value={formData.birth_place} onChange={(e) => setFormData({...formData, birth_place: e.target.value})} />
                <input type="text" placeholder="Nationality" value={formData.nationality} onChange={(e) => setFormData({...formData, nationality: e.target.value})} />
                <input type="text" placeholder="Religion" value={formData.religion} onChange={(e) => setFormData({...formData, religion: e.target.value})} />
              </div>
              <div className="form-row">
                <select value={formData.marital_status} onChange={(e) => setFormData({...formData, marital_status: e.target.value})}>
                  <option value="">Marital Status</option>
                  <option value="Single">Single</option>
                  <option value="Married">Married</option>
                  <option value="Divorced">Divorced</option>
                  <option value="Widowed">Widowed</option>
                </select>
                <input type="text" placeholder="Issued District" value={formData.issued_district} onChange={(e) => setFormData({...formData, issued_district: e.target.value})} />
                <input type="date" placeholder="Issued Date" value={formData.issued_date} onChange={(e) => setFormData({...formData, issued_date: e.target.value})} />
              </div>
              <div className="form-row">
                <input type="text" placeholder="Province" value={formData.province} onChange={(e) => setFormData({...formData, province: e.target.value})} />
                <input type="text" placeholder="District" value={formData.district} onChange={(e) => setFormData({...formData, district: e.target.value})} />
                <input type="text" placeholder="Municipality" value={formData.municipality} onChange={(e) => setFormData({...formData, municipality: e.target.value})} />
              </div>
              <div className="form-row">
                <input type="text" placeholder="Ward Number" value={formData.ward_number} onChange={(e) => setFormData({...formData, ward_number: e.target.value})} />
                <input type="text" placeholder="Tole/Street" value={formData.tole} onChange={(e) => setFormData({...formData, tole: e.target.value})} />
                <input type="text" placeholder="Phone" value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})} />
              </div>
              <div className="form-row">
                <input type="email" placeholder="Email" value={formData.email} onChange={(e) => setFormData({...formData, email: e.target.value})} />
              </div>

              <h3 style={{ marginTop: '20px', marginBottom: '15px', color: 'var(--text-primary)' }}>Document Photos</h3>
              <div className="photo-upload-section">
                <div className="photo-upload-item">
                  <label>Profile Photo</label>
                  <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'photo')} />
                  {(existingPhotos.photo || photos.photo) && (
                    <div className="photo-preview">
                      {existingPhotos.photo ? 
                        <img src={existingPhotos.photo} alt="Profile" /> : 
                        photos.photo && <img src={URL.createObjectURL(photos.photo)} alt="Profile Preview" />
                      }
                    </div>
                  )}
                </div>
                <div className="photo-upload-item">
                  <label>Citizenship Front</label>
                  <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'citizenship_front')} />
                  {(existingPhotos.citizenship_front || photos.citizenship_front) && (
                    <div className="photo-preview">
                      {existingPhotos.citizenship_front ? 
                        <img src={existingPhotos.citizenship_front} alt="Citizenship Front" /> : 
                        photos.citizenship_front && <img src={URL.createObjectURL(photos.citizenship_front)} alt="Front Preview" />
                      }
                    </div>
                  )}
                </div>
                <div className="photo-upload-item">
                  <label>Citizenship Back</label>
                  <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'citizenship_back')} />
                  {(existingPhotos.citizenship_back || photos.citizenship_back) && (
                    <div className="photo-preview">
                      {existingPhotos.citizenship_back ? 
                        <img src={existingPhotos.citizenship_back} alt="Citizenship Back" /> : 
                        photos.citizenship_back && <img src={URL.createObjectURL(photos.citizenship_back)} alt="Back Preview" />
                      }
                    </div>
                  )}
                </div>
              </div>

              <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Saving...' : (editingId ? 'Update Details' : 'Save Details')}
                </button>
                {editingId && (
                  <button type="button" className="btn-danger" onClick={handleDelete}>
                    Delete
                  </button>
                )}
              </div>
            </form>
          </div>

          {citizenshipData && (
            <div className="citizenship-preview-section">
              <h3>Saved Documents</h3>
              <div className="documents-grid">
                {existingPhotos.photo && (
                  <div className="document-card" onClick={() => viewPhoto(existingPhotos.photo, 'Profile Photo')}>
                    <div className="document-icon">📷</div>
                    <span>Profile Photo</span>
                  </div>
                )}
                {existingPhotos.citizenship_front && (
                  <div className="document-card" onClick={() => viewPhoto(existingPhotos.citizenship_front, 'Citizenship Front')}>
                    <div className="document-icon">🪪</div>
                    <span>Citizenship Front</span>
                  </div>
                )}
                {existingPhotos.citizenship_back && (
                  <div className="document-card" onClick={() => viewPhoto(existingPhotos.citizenship_back, 'Citizenship Back')}>
                    <div className="document-icon">🪪</div>
                    <span>Citizenship Back</span>
                  </div>
                )}
              </div>
            </div>
          )}
        </>
      )}

      {/* Photo Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setShowModal(false)}>×</button>
            <img src={existingPhotos.photo || existingPhotos.citizenship_front || existingPhotos.citizenship_back} alt="Document" />
          </div>
        </div>
      )}
    </div>
  );
}

// Protected Route
function ProtectedRoute({ children }) {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? children : <Navigate to="/login" />;
}

// Navigation
function Navigation() {
  const { logout } = useAuth();
  
  return (
    <nav className="sidebar">
      <div className="sidebar-header">
        <div className="logo">
          <svg viewBox="0 0 100 100" className="logo-svg">
            <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
            <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
            <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
          </svg>
        </div>
      </div>
      <div className="sidebar-nav">
        <Link to="/" className="nav-item"><span className="nav-icon">📊</span> Dashboard</Link>
        <Link to="/members" className="nav-item"><span className="nav-icon">👥</span> Members</Link>
        <Link to="/loans" className="nav-item"><span className="nav-icon">💰</span> Loans</Link>
        <Link to="/shares" className="nav-item"><span className="nav-icon">📈</span> Shares</Link>
        <Link to="/savings" className="nav-item"><span className="nav-icon">🏦</span> Savings</Link>
        <Link to="/monthly-savings" className="nav-item"><span className="nav-icon">📅</span> Monthly Savings</Link>
        <Link to="/profile" className="nav-item"><span className="nav-icon">👤</span> Profile</Link>
      </div>
      <div className="sidebar-footer">
        <button onClick={logout} className="logout-btn">Logout</button>
      </div>
    </nav>
  );
}

// Main App
function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    if (token && savedUser) {
      setIsAuthenticated(true);
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = (token, userData) => {
    localStorage.setItem('token', token);
    localStorage.setItem('user', JSON.stringify(userData));
    setIsAuthenticated(true);
    setUser(userData);
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ isAuthenticated, user, login, logout }}>
      <Router>
        <div className="app">
          {isAuthenticated && <Navigation />}
          <main className="main-content">
            <Routes>
              <Route path="/login" element={<LoginPage />} />
              <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
              <Route path="/members" element={<ProtectedRoute><MembersPage /></ProtectedRoute>} />
              <Route path="/loans" element={<ProtectedRoute><LoanPage /></ProtectedRoute>} />
              <Route path="/shares" element={<ProtectedRoute><SharePage /></ProtectedRoute>} />
              <Route path="/savings" element={<ProtectedRoute><SavingsPage /></ProtectedRoute>} />
              <Route path="/monthly-savings" element={<ProtectedRoute><MonthlySavingsPage /></ProtectedRoute>} />
              <Route path="/citizenship" element={<ProtectedRoute><CitizenshipPage /></ProtectedRoute>} />
              <Route path="/profile" element={<ProtectedRoute><ProfilePage /></ProtectedRoute>} />
            </Routes>
          </main>
        </div>
      </Router>
    </AuthContext.Provider>
  );
}

export default App;
